<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller;use App\Models\Category;use Illuminate\Http\{RedirectResponse,Request};use Illuminate\Support\Str;use Illuminate\View\View;
class CategoryController extends Controller{public function index():View{return view('admin.categories.index',['categories'=>Category::latest()->paginate(15)]);}public function create():View{return view('admin.categories.form',['category'=>new Category()]);}public function store(Request $r):RedirectResponse{$d=$r->validate(['name'=>'required','slug'=>'nullable','image'=>'nullable','description'=>'nullable','is_active'=>'nullable|boolean']);$d['slug']=$d['slug']?:Str::slug($d['name']);$d['is_active']=$r->boolean('is_active',true);Category::create($d);return redirect()->route('admin.categories.index');}public function edit(Category $category):View{return view('admin.categories.form',compact('category'));}public function update(Request $r,Category $category):RedirectResponse{$d=$r->validate(['name'=>'required','slug'=>'required','image'=>'nullable','description'=>'nullable','is_active'=>'nullable|boolean']);$d['is_active']=$r->boolean('is_active');$category->update($d);return redirect()->route('admin.categories.index');}public function destroy(Category $category):RedirectResponse{$category->delete();return back();}}
